function rebuildSummaryFromFullText(fullText) {
  const text = String(fullText || '')
    .replace(/\r/g, '')
    .replace(/\u000b/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  function esc(v) {
    return String(v).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  function section(start, ends) {
    const startRe = new RegExp(`(^|\\n)${esc(start)}\\s*\\n`, 'i');
    const startMatch = text.match(startRe);

    if (!startMatch) return '';

    const startIndex = startMatch.index + startMatch[0].length;
    let endIndex = text.length;

    for (const end of ends) {
      const slice = text.slice(startIndex);
      const endRe = new RegExp(`(^|\\n)${esc(end)}\\s*\\n`, 'i');
      const endMatch = slice.match(endRe);

      if (endMatch) {
        const candidateEnd = startIndex + endMatch.index;
        if (candidateEnd < endIndex) {
          endIndex = candidateEnd;
        }
      }
    }

    return text.substring(startIndex, endIndex).trim();
  }

  function clean(v) {
    return String(v || '')
      .replace(/Rate this Summary:[\s\S]*?(?=\n\n|$)/gi, '')
      .replace(/Let us know what you think:[\s\S]*?(?=\n\n|$)/gi, '')
      .replace(/^We've updated the Decisions section.*$/gim, '')
      .replace(/^ALIGNED$/gim, '')
      .replace(/Did the screenshots[\s\S]*?(?=\n|$)/gi, '')
      .replace(/You should review Gemini's notes[\s\S]*$/gi, '')
      .replace(/How is the quality[\s\S]*$/gi, '')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  const portfolioPerformance = clean(section('Portfolio Performance', [
    'Operational Issues',
    'Decisions',
    'Next steps',
    'Details'
  ]));

  const operationalIssues = clean(section('Operational Issues', [
    'Decisions',
    'Next steps',
    'Details'
  ]));

  const summary = clean(section('Summary', [
    'Decisions',
    'Next steps',
    'Details',
    'Rate this Summary'
  ]));

  const details = clean(section('Details', [
    "You should review Gemini's notes",
    'How is the quality'
  ]));

  const decisions = clean(section('Decisions', [
    'Next steps',
    'Details'
  ]));

  return {
    changes: portfolioPerformance
      ? [portfolioPerformance]
      : summary
        ? [summary]
        : [],

    issues: operationalIssues
      ? [operationalIssues]
      : details
        ? [details]
        : [],

    decisions: decisions ? [decisions] : []
  };
}

function normalizeOwner(owner) {
  const v = String(owner || '').trim().toLowerCase();

  if (v === 'brandon stewart' || v === 'brandon') return 'Brandon';
  if (v === 'tammie stewart' || v === 'tammy stewart' || v === 'tammy' || v === 'tammie') return 'Tammie';
  if (v === 'breanna blanks' || v === 'breanna' || v === 'brianna blanks' || v === 'brianna') return 'Breanna';
  if (v === 'amy') return 'Amy';
  if (v === 'debbie') return 'Debbie';
  if (v === 'dede') return 'Dede';
  if (v === 'shelbie') return 'Shelbie';
  if (v === 'chris') return 'Chris';
  if (v === 'ashlie' || v === 'ashlie wagner') return 'Ashlie';

  return String(owner || '').trim();
}

// Validate or repair summary_structured
let summaryStructured = $json.summary_structured;

const summaryShapeValid =
  summaryStructured &&
  Array.isArray(summaryStructured.changes) &&
  Array.isArray(summaryStructured.issues) &&
  Array.isArray(summaryStructured.decisions);

const summaryNeedsRepair =
  !summaryShapeValid ||
  summaryStructured.changes.length === 0 ||
  summaryStructured.issues.length === 0;

if (summaryNeedsRepair) {
  summaryStructured = rebuildSummaryFromFullText($json.full_text);
}

if (
  !summaryStructured ||
  !Array.isArray(summaryStructured.changes) ||
  !Array.isArray(summaryStructured.issues) ||
  !Array.isArray(summaryStructured.decisions)
) {
  throw new Error('Invalid summary_structured shape');
}

// Validate / normalize actions
let actions = Array.isArray($json.actions) ? $json.actions : [];

if (actions.length < 1) {
  throw new Error('At least 1 action is required');
}

if (actions.length > 25) {
  throw new Error(`Too many actions (${actions.length}). Possible parsing issue.`);
}

actions = actions.map((a, i) => {
  const description = a.action_description || a.description;
  const owner = normalizeOwner(a.action_owner || a.owner);

  if (!description || !String(description).trim()) {
    throw new Error(`Action ${i + 1} missing description`);
  }

  if (!owner || !String(owner).trim()) {
    throw new Error(`Action ${i + 1} missing owner`);
  }

  return {
    action_index: i + 1,
    action_description: String(description).trim(),
    action_owner: owner,
    due_date: a.due_date || null,
    status: a.status || 'open',
    property_name: a.property_name || null
  };
});

return [{
  json: {
    ...$json,
    summary_structured: summaryStructured,
    actions,
    action_count: actions.length
  }
}];

function makeUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function addDays(dateString, days) {
  const d = new Date(String(dateString).replace(' ', 'T'));
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

const meeting = $('Validate Meeting Payload').item.json;
const now = new Date().toISOString().slice(0, 19).replace('T', ' ');
const actions = meeting.actions || [];

const fallbackDueDate = addDays(meeting.meeting_datetime, 7);

return actions.map(action => ({
  json: {
    id: makeUuid(),
    meeting_id: meeting.id,
    manager_name: meeting.manager_name,
    property_name: action.property_name || null,
    action_description: action.action_description,
    action_owner: action.action_owner,
    due_date: action.due_date || fallbackDueDate,
    status: action.status || 'open',
    created_at: now,
    completed_at: null
  }
}));

const item = $json;

const allowedOwners = [
  item.manager_name,
  'Brandon',
  'Tammie',
  'Amy',
  'Breanna',
  'Debbie',
  'Dede',
  'Shelbie',
  'Chris',
  'Ashlie'
];

if (!allowedOwners.includes(item.action_owner)) {
  throw new Error(`Invalid action_owner: ${item.action_owner}`);
}

if (!/^\d{4}-\d{2}-\d{2}$/.test(String(item.due_date))) {
  throw new Error(`Invalid due_date format: ${item.due_date}`);
}

if (!item.action_description || !String(item.action_description).trim()) {
  throw new Error('Missing action_description');
}

if (!item.meeting_id || !String(item.meeting_id).trim()) {
  throw new Error('Missing meeting_id');
}

if (!item.manager_name || !String(item.manager_name).trim()) {
  throw new Error('Missing manager_name');
}

if (!item.status || !['open', 'completed', 'overdue'].includes(item.status)) {
  throw new Error(`Invalid status: ${item.status}`);
}

return {
  json: item
};

const meeting = $('Validate Meeting Payload').item.json;

// Pull from Expand Actions (the last place real rows exist)
const actionItems = $('Expand Actions').all().map(i => {
  const a = i.json;

  return {
    action_description: a.action_description,
    action_owner: a.action_owner,
    due_date: a.due_date,
    property_name: a.property_name
  };
});

return [{
  json: {
    success: true,
    meeting_id: meeting.id,
    manager_name: meeting.manager_name,
    meeting_datetime: meeting.meeting_datetime,
    week_reference: meeting.week_reference,
    summary_structured: meeting.summary_structured,
    actions: actionItems,
    action_count: actionItems.length
  }
}];

const rows = $input.all();

if (rows.length > 0 && rows[0].json && rows[0].json.id) {
  return [];
}

return [{
  json: $('Validate Meeting Payload').item.json
}];

